from typing import List, Tuple

class Pair:
    def __init__(self, first: int, second: int):
        self.first = first
        self.second = second

def max_chain_length(pairs: List[Pair], n: int) -> int:
    if not pairs:
        return 0

    # Sort pairs by their first element
    pairs.sort(key=lambda x: x.first)

    # dp[i] will store the maximum chain length ending at pair i
    dp = [1] * n

    for i in range(n):
        for j in range(i):
            if pairs[j].second < pairs[i].first:
                dp[i] = max(dp[i], dp[j] + 1)

    return max(dp)

