def largest_subset(nums, n):
    if n == 0:
        return 0
    if n == 1:
        return 1

    nums.sort()
    dp = [1] * n
    parent = [-1] * n

    for i in range(n):
        for j in range(i):
            if nums[i] % nums[j] == 0:
                if dp[j] + 1 > dp[i]:
                    dp[i] = dp[j] + 1
                    parent[i] = j

    max_len = max(dp)
    if max_len == 0:
        return 0

    # Reconstruct the subset
    subset = []
    curr = dp.index(max_len)
    while curr != -1:
        subset.append(nums[curr])
        curr = parent[curr]

    return len(subset)

